/// <summary>
/// This class handles the event when the InventLocationId field of the InventDim form data source is modified.
/// </summary>
final class ETGInventDimInventLocationId_EventHandler
{
}

Method.Source:
//NS, DLT ,04/03/2025  Location value should flow from PA to PO
/// <summary>
/// Event handler for the modification of the InventLocationId field in the PurchAgreement form.
/// </summary>
/// <param name="sender">The form data object that triggered the event.</param>
/// <param name="e">The form data field event arguments.</param>
[FormDataFieldEventHandler(formDataFieldStr(PurchAgreement, InventDim, InventLocationId), FormDataFieldEventType::Modified)]
public static void InventLocationId_OnModified(FormDataObject sender, FormDataFieldEventArgs e)
{
    if(ETGACFParameters::find().EnablePortLoadingDetailsHeaderToLine == NoYes::Yes)
    {
        FormDataSource inventDim_ds = sender.datasource();
        InventDim      inventDim    = inventDim_ds.cursor();

        inventDim.wMSLocationId = InventLocation::find(inventDim.InventLocationId).WMSLocationIdDefaultReceipt;
    }
}
//NE, DLT ,04/03/2025  Location value should flow from PA to PO
